#include "ior.h"
int fex(const char*f){return access(f,F_OK)==0;}
void ri(const char*f){int fd=open(f,O_RDONLY);if(fd<0){printf("No such input file found!\n");exit(1);}dup2(fd,STDIN_FILENO);close(fd);}
void ro(const char*f,int a){int fd=a?open(f,O_WRONLY|O_CREAT|O_APPEND,0644):open(f,O_WRONLY|O_CREAT|O_TRUNC,0644);if(fd<0){perror("output");exit(1);}dup2(fd,STDOUT_FILENO);close(fd);}
char*dc=NULL;
void hio(char*c,int fg){char*inf=NULL,*outf=NULL;int a=0;int oi=dup(STDIN_FILENO),oo=dup(STDOUT_FILENO);char*ir;int ff=0;if(strstr(c,">")&&strstr(c,"<")){dc=strdup(c);ir=strchr(dc,'<');ff=1;}else ir=strchr(c,'<');if(ir){*ir='\0';inf=strtok(ir+1," ");if(!fex(inf)){printf("No such input file found!\n");dup2(oi,STDIN_FILENO);dup2(oo,STDOUT_FILENO);close(oi);close(oo);return;}}char*or=strchr(c,'>');if(or){if(*(or+1)=='>'){a=1;*or='\0';outf=strtok(or+2," ");}else{*or='\0';outf=strtok(or+1," ");}}if(inf)ri(inf);if(outf)ro(outf,a);if(!ff){if(c&&strlen(c)>0)epi(c,fg);}else{if(dc&&strlen(dc)>0)epi(dc,fg);}fflush(stdout);dup2(oi,STDIN_FILENO);dup2(oo,STDOUT_FILENO);close(oi);close(oo);}
int ivc(const char*c){char*s=strdup(c);if(!s)return 0;int v=1,l=strlen(s);for(int i=0;i<l-1;i++)if(s[i]=='|'&&s[i+1]=='|'){v=0;break;}free(s);return v;}
void hp(char*c,int fg){char*cm[100];int cc=0;if(!ivc(c)){fprintf(stderr,"Invalid\n");return;}if(c[0]=='|'||c[strlen(c)-1]=='|'){fprintf(stderr,"Invalid use of pipe\n");return;}char*t=strtok(c,"|");while(t&&cc<100){while(*t==' ')t++;char*e=t+strlen(t)-1;while(e>t&&*e==' ')e--;*(e+1)='\0';if(strlen(t)==0){fprintf(stderr,"Invalid use of pipe\n");return;}cm[cc++]=t;t=strtok(NULL,"|");}if(cc==1){hio(cm[0],fg);return;}int oi=dup(STDIN_FILENO),oo=dup(STDOUT_FILENO),ps[99][2];for(int i=0;i<cc-1;i++)pipe(ps[i]);for(int i=0;i<cc;i++){if(i>0){dup2(ps[i-1][0],STDIN_FILENO);close(ps[i-1][0]);}if(i<cc-1){dup2(ps[i][1],STDOUT_FILENO);close(ps[i][1]);}if(i!=cc-1)hio(cm[i],0);else hio(cm[i],fg);if(i>0)dup2(oi,STDIN_FILENO);if(i<cc-1)dup2(oo,STDOUT_FILENO);}for(int i=0;i<cc-1;i++){close(ps[i][0]);close(ps[i][1]);}dup2(oi,STDIN_FILENO);dup2(oo,STDOUT_FILENO);close(oi);close(oo);}
